def process_users(db, user_ids):
    results = []
    for id in user_ids:
        query = f"SELECT * FROM users WHERE id = {id}"
        user = db.execute(query).fetchone()
        if user != None:
            user_dict = {}
            for key in user.keys():
                user_dict[key] = user[key]
            if user_dict['age'] > 0:
                user_dict['is_adult'] = user_dict['age'] >= 18
            results.append(user_dict)
    return results
```

Refactor this function to be cleaner and more Pythonic. Keep the same interface and behavior:

```python
def get_stats(numbers):
    if len(numbers) == 0:
        return None
    total = 0
    for n in numbers:
        total = total + n
    mean = total / len(numbers)
    sorted_nums = []
    for n in numbers:
        inserted = False
        for i in range(len(sorted_nums)):
            if n < sorted_nums[i]:
                sorted_nums.insert(i, n)
                inserted = True
                break
        if not inserted:
            sorted_nums.append(n)
    if len(sorted_nums) % 2 == 0:
        median = (sorted_nums[len(sorted_nums)//2 - 1] + sorted_nums[len(sorted_nums)//2]) / 2
    else:
        median = sorted_nums[len(sorted_nums)//2]
    return {'mean': mean, 'median': median, 'min': sorted_nums[0], 'max': sorted_nums[-1]}
```

This function should flatten a nested dictionary but it has bugs. Fix it and explain what was wrong:

```python
def flatten_dict(d, parent_key='', sep='.'):
    items = []
    for k, v in d.items():
        new_key = parent_key + sep + k if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep=sep))
        else:
            items.append((new_key, v))
    return items
```

